            del self.events[name]
            return True
        return False

    def next_event(self, t):
        valid_events = {name: (start, end) for name, (start, end) in self.events.items() if start >= t}
        if not valid_events:
            return None
        return min(valid_events, key=lambda k: valid_events[k][0])

    def count(self):
